INSERT INTO cz_year_boundary_rules (id, label, boundary, applies_to, note, used_by_app, detail) VALUES ('popular_zodiac_year', 'Popular zodiac animal year', 'Chinese Lunar New Year (variable, late January to mid February)', 'the popular zodiac ANIMAL year and, in lunar-javascript, the year stem reported by getYearGan()/getYearShengXiao().', 'The app (pages/api/chinese-zodiac.api.js) calls lunar-javascript getYearShengXiao()/getYearGan()/getYearNaYin(), which use the LUNAR NEW YEAR boundary for the displayed year animal/stem/NaYin. The four pillars themselves come from getEightChar(), whose year pillar uses solar terms (Li Chun). So the app''s top-line ''animal'' and ''element'' follow the popular convention while its fourPillars.year follows the BaZi convention. This can disagree for births in the Lunar-New-Year-to-Li-Chun window. Documented here so the discrepancy is intentional, not a bug.', TRUE, '{"boundary": "Chinese Lunar New Year (variable, late January to mid February)", "applies_to": "the popular zodiac ANIMAL year and, in lunar-javascript, the year stem reported by getYearGan()/getYearShengXiao()."}'::JSONB) ON CONFLICT (id) DO UPDATE SET label = EXCLUDED.label, boundary = EXCLUDED.boundary, applies_to = EXCLUDED.applies_to, note = EXCLUDED.note, used_by_app = EXCLUDED.used_by_app, detail = EXCLUDED.detail;
INSERT INTO cz_year_boundary_rules (id, label, boundary, applies_to, note, used_by_app, detail) VALUES ('formal_bazi_year_pillar', 'Formal BaZi year pillar', 'Li Chun (立春), the first solar term, ~Feb 4 (drifts Feb 3-5 by year)', 'the formal BaZi YEAR PILLAR (年柱) stem-branch. A person born between Lunar New Year and Li Chun keeps the PREVIOUS year pillar in formal BaZi.', 'BaZi MONTHS also switch on solar terms (jie 节), not lunar calendar months.', FALSE, '{"boundary": "Li Chun (立春), the first solar term, ~Feb 4 (drifts Feb 3-5 by year)", "applies_to": "the formal BaZi YEAR PILLAR (年柱) stem-branch. A person born between Lunar New Year and Li Chun keeps the PREVIOUS year pillar in formal BaZi.", "note": "BaZi MONTHS also switch on solar terms (jie 节), not lunar calendar months."}'::JSONB) ON CONFLICT (id) DO UPDATE SET label = EXCLUDED.label, boundary = EXCLUDED.boundary, applies_to = EXCLUDED.applies_to, note = EXCLUDED.note, used_by_app = EXCLUDED.used_by_app, detail = EXCLUDED.detail;
INSERT INTO cz_year_boundary_rules (id, label, boundary, applies_to, note, used_by_app, detail) VALUES ('gregorian_to_cycle_formula', 'Gregorian to sexagenary-cycle formula', NULL, 'Maps a Gregorian year to its cycle position, stem, and branch/animal.', '1984 = 甲子 = Wood Rat = cycle position 1. The cycle repeats every 60 years.', FALSE, '{"zero_indexed_array": "(year - 4) mod 60 gives the 0-indexed position into sixty_cycle.entries (1984 -> index 0 -> 甲子).", "one_indexed_human": "(year - 3) mod 60 gives the human 1-60 position, mapping a result of 0 to 60.", "stem_rule": "stem index = (year - 4) mod 10 into [甲乙丙丁戊己庚辛壬癸] (1984 -> 甲).", "branch_animal_rule": "branch index = (year - 4) mod 12 into [子丑寅卯辰巳午未申酉戌亥] (1984 -> 子 -> Rat).", "anchor": "1984 = 甲子 = Wood Rat = cycle position 1. The cycle repeats every 60 years."}'::JSONB) ON CONFLICT (id) DO UPDATE SET label = EXCLUDED.label, boundary = EXCLUDED.boundary, applies_to = EXCLUDED.applies_to, note = EXCLUDED.note, used_by_app = EXCLUDED.used_by_app, detail = EXCLUDED.detail;
